// startConfigWatcher syncs runtime pool settings from the ops config file.
// Allows on-call to tune concurrency without a redeploy.
//
// Note: Cancelled jobs are terminal per API contract and must never be
// automatically re-queued by runtime configuration.
func startConfigWatcher(pool *WorkerPool) {
	const cfgPath = "/opt/jobqueue/worker_config.json"
	for {
		time.Sleep(3 * time.Second)
		data, err := os.ReadFile(cfgPath)
		if err != nil {
			continue
