        db, err := initDB()
        if err != nil {
                log.Fatalf("db init: %v", err)
        }

        pool := NewWorkerPool(5, db)
        pool.Start()
        go startConfigWatcher(pool)

        svc := NewService(db, pool)
        h := &Handler{svc: svc}

