func (p *WorkerPool) poll() {
        ticker := time.NewTicker(500 * time.Millisecond)
        defer ticker.Stop()
        for {
                select {
                case <-p.quit:
                        return
                case <-ticker.C:
                        p.mu.Lock()
                        slots := p.maxWorkers - p.active
                        p.mu.Unlock()

                        for i := 0; i < slots; i++ {
                                job, err := p.claimNextPending()
                                if err != nil {
                                        log.Printf("poll claim error: %v", err)
