                                }
                                if job == nil {
                                        break
                                }
                                p.mu.Lock()
                                p.active++
                                p.mu.Unlock()

                                go func(jobID int) {
                                        defer func() {
                                                p.mu.Lock()
                                                p.active--
                                                p.mu.Unlock()
                                        }()
                                        p.process(jobID)
                                }(job.id)
                        }
                }
        }
}

